compliant:
char dest[50] = "Hello";
char *src = "World";
if (strlen(dest) + strlen(src) + 1 <= sizeof(dest)) {
    strncat(dest, src, sizeof(dest) - strlen(dest) - 1); // Compliant: check bounds
}

// Or use safer alternatives:
char result[100];
snprintf(result, sizeof(result), "%s%s", dest, src); // Compliant: snprintf is safer
